A debounce function is a higher-order function that delays the execution of another function until after a specified period of inactivity, preventing it from being called too frequently.

```javascript
function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example usage:
function logMessage(message) {
  console.log(`Message: ${message}`);
}

const debouncedLog = debounce(logMessage, 1000);  // Debounce by 1 second

// Simulate calls: If you call debouncedLog('Hello') multiple times quickly, it will only execute after 1 second of no calls.
debouncedLog('Hello');  // This will log after 1 second if no further calls are made.
debouncedLog('World');  // This resets the timer; it will log 'World' after 1 second of no further calls.
```
